<script setup lang="ts">
import{computed,ref,watch}from"vue";import type{UserRole}from"@moecraft/shared";import{navigationForRoles}from"../../router/navigation";import SidebarNavItem from"./SidebarNavItem.vue";
const props=defineProps<{activePage:string;roles:UserRole[]}>();const emit=defineEmits<{select:[page:string]}>();const items=computed(()=>navigationForRoles(props.roles));const expanded=ref<Set<string>>(new Set(JSON.parse(localStorage.getItem("mc-admin-nav-expanded")??"[]") as string[]));
function ensureActive(){for(const item of items.value)if(item.children?.some(child=>child.routeName===props.activePage))expanded.value.add(item.id)}function toggle(id:string){const next=new Set(expanded.value);next.has(id)?next.delete(id):next.add(id);expanded.value=next;localStorage.setItem("mc-admin-nav-expanded",JSON.stringify([...next]))}watch(()=>[props.activePage,...props.roles],ensureActive,{immediate:true});
</script>
<template><aside class="sidebar"><div class="brand"><span>M</span><div><b>MoeCraft</b><small>MERCHANT CONSOLE</small></div></div><nav aria-label="后台主导航"><SidebarNavItem v-for="item in items" :key="item.id" :item="item" :active-page="activePage" :expanded="expanded.has(item.id)" @toggle="toggle" @navigate="emit('select',$event)"/></nav><div class="version"><span>MC</span><div><b>Console</b><small>v0.12</small></div></div></aside></template>
<style scoped>.sidebar{display:flex;width:236px;height:100%;flex-direction:column;flex-shrink:0;padding:18px 14px;border-right:1px solid var(--border);background:var(--surface)}.brand{display:flex;align-items:center;gap:11px;padding:4px 8px 22px}.brand>span{display:grid;width:38px;height:38px;place-items:center;border-radius:12px;background:linear-gradient(145deg,#6957e8,#9d6be7);box-shadow:0 8px 16px #6957e838;color:#fff;font-size:19px;font-weight:700}.brand div,.version div{display:grid}.brand b{color:var(--text);font-size:15px}.brand small,.version small{color:var(--text-muted);font-size:8px;letter-spacing:.12em}nav{display:flex;min-height:0;flex:1;flex-direction:column;gap:5px;overflow:auto}.version{display:flex;align-items:center;gap:9px;padding:12px;margin-top:12px;border-radius:10px;background:var(--surface-raised)}.version>span{display:grid;width:27px;height:27px;place-items:center;border-radius:8px;background:var(--accent-soft);color:var(--accent);font-size:9px;font-weight:700}.version b{color:var(--text-secondary);font-size:10px}@media(max-width:860px){.sidebar{width:68px;padding:14px 9px}.brand{padding:4px 6px 20px}.brand div,.version{display:none}}
</style>
